import classnames from "classnames"
import logo from "../assets/images/eye.png"

const Navbar = ({ visible } : {visible:boolean}) => (
  <nav className={classnames("navbar", {"navbar__hidden": !visible})}>
    <div className="navbar__container">
      <img className="navbar__logo" src={logo} alt="Nav Logo" />
      <h1 className="navbar__title">VibeBlind</h1>
    </div>
    <ul className="navbar__list">
      <li className="navbar__item">
        <a href="#">About</a>
      </li>
      <li className="navbar__item">
        <a href="#">Contact</a>
      </li>
    </ul>
  </nav>
)

export default Navbar